// sqft from mm dimensions: L * H / 1,000,000 * 10.764
const calcSqft = (l, h) => {
    const v = (parseFloat(l) || 0) * (parseFloat(h) || 0) / 1_000_000 * 10.764;
    return v > 0 ? v.toFixed(3) : "—";
};
const calcSqmtr = (sqft) => {
    const v = (parseFloat(sqft) || 0) / 10.764;
    return v > 0 ? v.toFixed(3) : "—";
};
const calcPayment = (sqmtr, rate, pct) => {
    const v = (parseFloat(sqmtr) || 0) * (parseFloat(rate) || 0) * pct;
    return v > 0 ? `₹ ${v.toLocaleString("en-IN", { maximumFractionDigits: 0 })}` : "—";
};

