// ─── PLACEHOLDER COMPONENTS ──────────────────────────────────────────────────
function MTOTypeSection({ type, stages }) {
    const demoProgress = 3;
    return (
        <div className="mto-section">
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                <div style={{ display:"flex", alignItems:"center", gap:"10px" }}>
                    <span style={{ fontSize:"22px" }}>{type.emoji}</span>
                    <span style={{ fontWeight:700, color:"#1e293b", fontSize:"15px" }}>{type.label} MTO</span>
                </div>
                <button style={{ ...styles.smallBtn, background:type.color }}>+ New MTO</button>
            </div>
            <div className="pipeline-row">
                {stages.map((stage, idx) => {
                    const status = idx < demoProgress ? "done" : idx === demoProgress ? "active" : "pending";
                    return (
                        <React.Fragment key={stage}>
                            <div className="pip-step">
                                <div className={`pip-dot ${status}`}>{status==="done" ? "✓" : idx+1}</div>
                                <div className="pip-label">{stage}</div>
                            </div>
                            {idx < stages.length-1 && <div className={`pip-connector ${idx < demoProgress-1 ? "done-line" : ""}`}/>}
                        </React.Fragment>
                    );
                })}
            </div>
        </div>
    );
}

